// MARK: - NetworkConfiguration.swift

import Foundation

enum APIEnvironment {
    case production
    case legacy
    
    var baseURL: URL {
        switch self {
        case .production:
            return URL(string: "https://api.example.com")!
        case .legacy:
            return URL(string: "http://legacy.internal")!
        }
    }
    
    var requiresSecureConnection: Bool {
        switch self {
        case .production:
            return true
        case .legacy:
            return false
        }
    }
}

// MARK: - SSLPinningDelegate.swift

import Foundation
import Security

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // SHA-256 hashes of the public keys for certificate pinning on production
    private let pinnedPublicKeyHashes: [String: Set<String>] = [
        "api.example.com": [
            "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=", // Primary certificate hash
            "CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="  // Backup certificate hash
        ]
    ]
    
    private let trustedLegacyDomains: Set<String> = [
        "legacy.internal"
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // For legacy internal domains, allow the connection but log a warning
        if trustedLegacyDomains.contains(host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For production domains, perform certificate pinning
        guard let pinnedHashes = pinnedPublicKeyHashes[host] else {
            // Unknown host — reject
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Extract public key and compute hash
        if let publicKey = SecCertificateCopyKey(serverCertificate),
           let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? {
            let hash = publicKeyData.sha256Base64()
            if pinnedHashes.contains(hash) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        
        // Pin mismatch — reject
        completionHandler(.cancelAuthenticationChallenge, nil)
    }
}

// MARK: - Data+SHA256.swift

import Foundation
import CommonCrypto

extension Data {
    func sha256Base64() -> String {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        self.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(self.count), &hash)
        }
        return Data(hash).base64EncodedString()
    }
}

// MARK: - NetworkError.swift

import Foundation

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case httpError(statusCode: Int, data: Data?)
    case networkError(Error)
    case insecureConnectionBlocked
    case sslPinningFailed
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .httpError(let statusCode, _):
            return "HTTP error: \(statusCode)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .insecureConnectionBlocked:
            return "Insecure connection blocked by policy"
        case .sslPinningFailed:
            return "SSL certificate pinning validation failed"
        }
    }
}

// MARK: - APIClient.swift

import Foundation
import os.log

final class APIClient {
    
    static let shared = APIClient()
    
    private let productionSession: URLSession
    private let legacySession: URLSession
    private let sslPinningDelegate: SSLPinningDelegate
    private let logger = Logger(subsystem: "com.app.networking", category: "APIClient")
    
    private init() {
        self.sslPinningDelegate = SSLPinningDelegate()
        
        // Production session with SSL pinning and strict TLS
        let productionConfig = URLSessionConfiguration.default
        productionConfig.tlsMinimumSupportedProtocolVersion = .TLSv12
        productionConfig.timeoutIntervalForRequest = 30
        productionConfig.timeoutIntervalForResource = 60
        productionConfig.waitsForConnectivity = true
        productionConfig.requestCachePolicy = .reloadIgnoringLocalCacheData
        self.productionSession = URLSession(
            configuration: productionConfig,
            delegate: sslPinningDelegate,
            delegateQueue: nil
        )
        
        // Legacy session for internal on-premise systems
        let legacyConfig = URLSessionConfiguration.default
        legacyConfig.timeoutIntervalForRequest = 45
        legacyConfig.timeoutIntervalForResource = 120
        legacyConfig.waitsForConnectivity = true
        self.legacySession = URLSession(
            configuration: legacyConfig,
            delegate: sslPinningDelegate,
            delegateQueue: nil
        )
    }
    
    // MARK: - Generic Request Methods
    
    func request<T: Decodable>(
        environment: APIEnvironment,
        path: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil,
        responseType: T.Type
    ) async throws -> T {
        let url = environment.baseURL.appendingPathComponent(path)
        
        var urlRequest = URLRequest(url: url)
        urlRequest.httpMethod = method.rawValue
        urlRequest.httpBody = body
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add custom headers
        headers?.forEach { key, value in
            urlRequest.setValue(value, forHTTPHeaderField: key)
        }
        
        let session = sessionForEnvironment(environment)
        
        logger.info("[\(environment)] \(method.rawValue) \(url.absoluteString)")
        
        if !environment.requiresSecureConnection {
            logger.warning("⚠️ Making insecure HTTP request to \(url.host ?? "unknown") — legacy system")
        }
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.noData
            }
            
            logger.info("[\(environment)] Response: \(httpResponse.statusCode)")
            
            guard (200...299).contains(httpResponse.statusCode) else {
                throw NetworkError.httpError(statusCode: httpResponse.statusCode, data: data)
            }
            
            do {
                let decoder = JSONDecoder()
                decoder.dateDecodingStrategy = .iso8601
                decoder.keyDecodingStrategy = .convertFromSnakeCase
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
        } catch let error as NetworkError {
            throw error
        } catch {
            throw NetworkError.networkError(error)
        }
    }
    
    func requestRaw(
        environment: APIEnvironment,
        path: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil
    ) async throws -> (Data, HTTPURLResponse) {
        let url = environment.baseURL.appendingPathComponent(path)
        
        var urlRequest = URLRequest(url: url)
        urlRequest.httpMethod = method.rawValue
        urlRequest.httpBody = body
        
        headers?.forEach { key, value in
            urlRequest.setValue(value, forHTTPHeaderField: key)
        }
        
        let session = sessionForEnvironment(environment)
        
        logger.info("[\(environment)] \(method.rawValue) \(url.absoluteString)")
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }
        
        return (data, httpResponse)
    }
    
    // MARK: - Private Helpers
    
    private func sessionForEnvironment(_ environment: APIEnvironment) -> URLSession {
        switch environment {
        case .production:
            return productionSession
        case .legacy:
            return legacySession
        }
    }
}

