// MARK: - ProductionAPIService.swift

final class ProductionAPIService {
    
    private let client = APIClient.shared
    
    func fetchUsers() async throws -> [User] {
        let response: APIResponse<[User]> = try await client.request(
            environment: .production,
            path: "/v1/users",
            method: .get,
            responseType: APIResponse<[User]>.self
        )
        return response.data ?? []
    }
    
    func createUser(name: String, email: String) async throws -> User {
        let body = try JSONEncoder().encode(["name": name, "email": email])
        let response: APIResponse<User> = try await client.request(
            environment: .production,
            path: "/v1/users",
            method: .post,
            body: body,
            responseType: APIResponse<User>.self
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    func fetchUser(id: Int) async throws -> User {
        let response: APIResponse<User> = try await client.request(
            environment: .production,
            path: "/v1/users/\(id)",
            method: .get,
            responseType: APIResponse<User>.self
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
}

