// MARK: - ContentViewModel.swift

import SwiftUI

@MainActor
final class ContentViewModel: ObservableObject {
    
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var isLoadingUsers = false
    @Published var isLoadingRecords = false
    @Published var errorMessage: String?
    @Published var showError = false
    
    private let productionService = ProductionAPIService()
    private let legacyService = LegacyAPIService()
    
    func loadUsers() async {
        isLoadingUsers = true
        errorMessage = nil
        
        do {
            users = try await productionService.fetchUsers()
        } catch {
            errorMessage = error.localizedDescription
            showError = true
        }
        
        isLoadingUsers = false
    }
    
    func loadLegacyRecords() async {
        isLoadingRecords = true
        errorMessage = nil
        
        do {
            legacyRecords = try await legacyService.fetchRecords()
        } catch {
            errorMessage = error.localizedDescription
            showError = true
        }
        
        isLoadingRecords = false
    }
    
    func loadAll() async {
        async let usersTask: () = loadUsers()
        async let recordsTask: () = loadLegacyRecords()
        _ = await (usersTask, recordsTask)
    }
}

